import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import './Sidebar.css';

const Sidebar = () => {
  const { user } = useAuth();
  const isAdmin = user?.role === 'admin';

  // Customer Navigation Items
  const customerNavItems = [
    { 
      name: 'Dashboard', 
      path: '/customer/dashboard', 
      icon: '📊',
      description: 'Overview & stats'
    },
    { 
      name: 'Transactions', 
      path: '/customer/transactions', 
      icon: '📝',
      description: 'Purchase history'
    },
    { 
      name: 'Ratings', 
      path: '/customer/ratings', 
      icon: '⭐',
      description: 'Your reviews',
      badge: 'new'
    },
    { 
      name: 'Returns', 
      path: '/customer/returns', 
      icon: '↩️',
      description: 'Return requests'
    },
    { 
      name: 'Messages', 
      path: '/customer/messages', 
      icon: '💬',
      description: 'Support chats'
    },
    { 
      name: 'Profile', 
      path: '/customer/profile', 
      icon: '👤',
      description: 'Account settings'
    },
  ];

  // Admin Navigation Items
  const adminNavItems = [
    { 
      name: 'Dashboard', 
      path: '/admin/dashboard', 
      icon: '📊',
      description: 'Overview'
    },
    { 
      name: 'Sensors', 
      path: '/admin/sensors', 
      icon: '📡',
      description: 'Machine status'
    },
    { 
      name: 'Transactions', 
      path: '/admin/transactions', 
      icon: '📝',
      description: 'All purchases'
    },
    { 
      name: 'Returns', 
      path: '/admin/returns', 
      icon: '↩️',
      description: 'Return requests'
    },
    { 
      name: 'Ratings', 
      path: '/admin/ratings', 
      icon: '⭐',
      description: 'Customer reviews',
      badge: 'pending'
    },
    { 
      name: 'Messages', 
      path: '/admin/messages', 
      icon: '💬',
      description: 'Support tickets'
    },
    { 
      name: 'Reports', 
      path: '/admin/reports', 
      icon: '📈',
      description: 'Analytics'
    },
    { 
      name: 'Users', 
      path: '/admin/users', 
      icon: '👥',
      description: 'Manage users'
    },
  ];

  const navItems = isAdmin ? adminNavItems : customerNavItems;

  return (
    <aside className="sidebar">
      <div className="sidebar-header">
        <div className="sidebar-logo">
          <h2>AgriVend</h2>
          <p>{isAdmin ? 'Admin Panel' : 'Customer Portal'}</p>
        </div>
      </div>
      
      <nav className="sidebar-nav">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) => 
              `sidebar-link ${isActive ? 'active' : ''}`
            }
          >
            <span className="link-icon">{item.icon}</span>
            <span className="link-text">
              <span className="link-name">{item.name}</span>
              <span className="link-description">{item.description}</span>
            </span>
            {item.badge && (
              <span className={`link-badge ${item.badge}`}>{item.badge}</span>
            )}
          </NavLink>
        ))}
      </nav>

      <div className="sidebar-footer">
        <div className="user-info">
          <div className="user-avatar">
            {user?.firstName?.charAt(0)}{user?.lastName?.charAt(0)}
          </div>
          <div className="user-details">
            <div className="user-name">{user?.firstName} {user?.lastName}</div>
            <div className="user-role">{isAdmin ? 'Administrator' : 'Customer'}</div>
          </div>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;
